<?php
namespace StepSystem\Controllers;
use StepSystem\Core\View;use StepSystem\Core\Auth;use StepSystem\Core\Flash;use StepSystem\Core\Database;
class UserController{
 public function dashboard(){Auth::requireLogin();View::render('dashboard',['title'=>'用户中心','user'=>Auth::user()]);}
 public function profile(){redirect('index.php?r=dashboard');}
 public function password(){Auth::requireLogin();if($_SERVER['REQUEST_METHOD']==='POST'){if(!hash_equals($_SESSION['csrf_token']??'',(string)($_POST['csrf_token']??''))){http_response_code(403);exit('CSRF validation failed');}$o=$_POST['old_password']??'';$n=$_POST['new_password']??'';$x=Auth::user();$isAdmin=($x['role']??'')==='admin';$newUsername=trim((string)($_POST['username']??$x['username']));if(!password_verify($o,$x['password'])){Flash::set('原密码错误','error');redirect('index.php?r=password');}if($isAdmin){if(mb_strlen($newUsername)<3||mb_strlen($newUsername)>64){Flash::set('管理员用户名长度需为 3-64 位','error');redirect('index.php?r=password');}$s=Database::pdo()->prepare('SELECT id FROM users WHERE username=? AND id<>? LIMIT 1');$s->execute([$newUsername,$x['id']]);if($s->fetch()){Flash::set('该用户名已存在，请换一个','error');redirect('index.php?r=password');}}$data=[];$args=[];if($isAdmin&&$newUsername!==$x['username']){$data[]='username=?';$args[]=$newUsername;}if($n!==''){if(strlen($n)<6){Flash::set('新密码至少 6 位','error');redirect('index.php?r=password');}$data[]='password=?';$args[]=password_hash($n,PASSWORD_DEFAULT);}if(!$data){Flash::set('没有需要保存的修改','error');redirect('index.php?r=password');}$args[]=$x['id'];Database::pdo()->prepare('UPDATE users SET '.implode(',',$data).' WHERE id=?')->execute($args);Auth::refresh();Flash::set($isAdmin?'账号信息修改成功':'密码修改成功');redirect('index.php?r=dashboard');}View::render('password',['title'=>'账号与密码','user'=>Auth::user()]);}
}